def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for a in range(1, 15):
                decay = np.exp(-ratio * a * 1.2)
                power = a ** 3.1
                weight = 1.0
                if a % 4 == 0:
                    weight = 0.85
                elif a % 5 == 0:
                    weight = 1.1
                temp = decay * power * weight
                if a % 2 == 0:
                    temp += np.log1p(a)
                score += temp
            mod_cond = (capacity + item) % 4 == 0 or (capacity - item) % 7 == 0
            if mod_cond:
                score *= 0.82
            if score > 12:
                score /= 3.1
            if capacity > 50:
                score += np.sin(capacity) * 2.3
        elif 0.05 <= ratio < 0.2:
            prod = 1.0
            for n in range(1, int(capacity) + 3):
                val = (ratio + n / (n + 2)) ** 1.1
                prod *= val
                if prod > 5e6:
                    prod = np.log1p(prod) * 1.3
                    break
            mod_val = int(prod * 1.7) % 350
            score += np.sqrt(ratio * mod_val + 2)
            if (int(capacity) % 5 == 0) and ((item * 5) % 4 == 0):
                score += 5.2
            else:
                score -= 1.1
            extra_sum = 0
            for x in range(1, 8):
                extra_sum += ((ratio * x**3) % 1) * (x ** 2.5)
            score += extra_sum / 7
            if capacity < 20 and score > 10:
                score -= 4.5
        elif 0.2 <= ratio <= 0.5:
            for m in range(1, 9):
                base = (ratio ** (m + 3)) * (m ** 3.1) / ((m + 3) ** 1.1)
                mod_factor = np.cos(m + ratio * 5)
                increment = base * (1 + 0.5 * mod_factor)
                score += increment
            remainder = capacity - item
            if remainder < 4:
                score += 12 + remainder * 0.7
            else:
                score -= remainder * 1.1
            if score < -7:
                score = abs(score) * 0.4 + 3.5
            if int(capacity) % 9 == 0:
                score *= 1.35
            if score > 20:
                score /= 2.8
            if item > 50:
                score *= 1.15
        elif 0.5 < ratio <= 0.8:
            penalty_base = 0
            for p in range(1, 12):
                term = ((ratio - 0.5) ** p) * (p ** 2.1) * np.sin(p + ratio * 10)
                penalty_base += term
                if penalty_base > 70:
                    penalty_base = np.log1p(abs(penalty_base)) * 1.5
                    break
            score = penalty_base * 14
            if capacity < item * 1.1:
                score += 18
            if (int(capacity * 4) % 8 == 0) and (int(item * 7) % 13 == 0):
                score -= 7.5
            if score < 0:
                score *= -1.8
                score += 6.2
            if score > 130:
                score = 130
            if capacity < 10:
                score += 4
        elif 0.8 < ratio <= 1.2:
            penalty_ext = 0
            diff = ratio - 0.8
            for q in range(1, 13):
                inner = ((diff) ** q) * (q ** 2.9) / (q + 0.8)
                if q % 2 == 0:
                    inner *= np.cos(q * ratio)
                penalty_ext += inner
                if penalty_ext > 1500:
                    penalty_ext = np.log1p(abs(penalty_ext)) * 2
                    break
            score = penalty_ext * 18
            if capacity < item * 1.4:
                score += 22
            if (int(capacity * 2) % 6 == 0) and (int(item * 11) % 5 == 0):
                score -= 9
            for z in range(1, 8):
                score += ((diff / (z + 0.7)) % 1) * (z * 2.1)
            if score < 0:
                score = abs(score) * 0.6
            if score > 1800:
                score = 1800
        elif 1.2 < ratio <= 1.8:
            super_penalty = 0
            diff = ratio - 1.2
            for r in range(1, 15):
                term = ((diff) ** r) * (r ** 3.4)
                if term > 15000:
                    term = np.sqrt(term) * 1.1
                super_penalty += term
                if super_penalty > 25000:
                    super_penalty = np.log1p(abs(super_penalty)) * 3
                    break
            score = super_penalty * 30
            if capacity < item * 2.5:
                score += 32
            if (int(capacity * 15) % 7 == 0) and (int(item * 19) % 6 == 0):
                score -= 12
            for w in range(2, 9):
                score += ((diff / w) % 1) * (w * 2.8)
            if score < 0:
                score = abs(score) * 0.8 + 6
            if score > 2800:
                score = 2800
        else:
            mega_penalty = 0
            diff = ratio - 1.8
            for s in range(1, 17):
                term = ((diff) ** s) * (s ** 3.6) * np.abs(np.sin(s * diff))
                if term > 20000:
                    term = np.cbrt(term) * 1.3
                mega_penalty += term
                if mega_penalty > 35000:
                    mega_penalty = np.log1p(abs(mega_penalty)) * 3.5
                    break
            score = mega_penalty * 28
            if capacity < item * 3:
                score += 40
            if (int(capacity * 17) % 5 == 0) and (int(item * 23) % 7 == 0):
                score -= 15
            for u in range(3, 11):
                score += ((diff / u) % 1) * (u * 3)
            if score < 0:
                score = abs(score) * 0.9 + 8
            if score > 3500:
                score = 3500
        if capacity > 300:
            score /= (np.log1p(capacity) + 1.5)
        elif capacity < 8:
            score *= 2.5
        if abs(score) > 2000:
            score = np.sign(score) * 2000
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        fill_value = np.max(finite_priorities) * (20 + top_count) - median_val * 0.9
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
